        .project-details h3 { margin: 0; font-size: 24px; font-weight: 400; font-family: 'Playfair Display', serif; }

        .project-year-box { display: flex; align-items: center; gap: 15px; margin-top: 8px; }
        .year-line { width: 30px; height: 1px; background: var(--border); }
        .year { font-size: 12px; color: var(--text-dim); font-variant-numeric: tabular-nums; }

        .archive-wrapper { text-align: center; margin-top: 120px; }
        .archive-toggle-btn {
          background: transparent; border: none; color: var(--text);
          font-size: 12px; text-transform: uppercase; letter-spacing: 0.3em;
          cursor: pointer; display: inline-flex; align-items: center; gap: 15px; padding: 20px;
        }
        .btn-icon { width: 40px; height: 40px; border: 1px solid var(--border); border-radius: 50%; display: flex; align-items: center; justify-content: center; transition: 0.3s; }
        .archive-toggle-btn:hover .btn-icon { background: var(--accent); border-color: var(--accent); color: #000; }

        .archive-grid { display: grid; grid-template-columns: repeat(4, 1fr); gap: 30px; margin-top: 60px; text-align: left; }
        .archive-img-box { aspect-ratio: 1; overflow: hidden; margin-bottom: 20px; border: 1px solid var(--border); }
        .archive-img-box img { width: 100%; height: 100%; object-fit: cover; opacity: 0.5; transition: 0.5s; }
        .archive-item:hover img { opacity: 1; }
        .archive-info h4 { margin: 0 0 5px; font-size: 16px; font-weight: 500; }
        .archive-info p { margin: 0; font-size: 11px; color: var(--text-dim); text-transform: uppercase; }

        .main-footer { background: #070708; padding: 150px 0 60px; border-top: 1px solid var(--border); position: relative; }
        .footer-container { max-width: 1400px; margin: 0 auto; padding: 0 50px; display: flex; flex-direction: column; align-items: center; }
        .footer-heading { font-family: 'Playfair Display', serif; font-size: clamp(30px, 5vw, 60px); font-style: italic; margin: 20px 0 60px; }

        .footer-links { display: flex; gap: 60px; margin-bottom: 100px; }
        .sliding-link {
          font-size: 24px; color: var(--text); text-decoration: none; font-weight: 300;
          position: relative; transition: 0.3s;
        }
        .sliding-link:hover { color: var(--accent); }

        .footer-bottom { width: 100%; display: flex; justify-content: space-between; align-items: center; padding-top: 40px; border-top: 1px solid var(--border); }
        .copyright { font-size: 10px; text-transform: uppercase; letter-spacing: 0.3em; color: var(--text-dim); }
        .footer-dot { width: 6px; height: 6px; background: var(--accent); border-radius: 50%; }

        @keyframes fadeInUp {
          from { opacity: 0; transform: translateY(40px); }
          to { opacity: 1; transform: translateY(0); }
        }

        @media (max-width: 1024px) {
          .projects-grid { grid-template-columns: 1fr; gap: 60px; }
          .archive-grid { grid-template-columns: 1fr 1fr; }
        }

        @media (max-width: 768px) {
          .header { padding: 20px; }
          .desktop-nav { display: none; }
          .hero-section { padding-top: 200px; }
          .footer-links { flex-direction: column; gap: 30px; align-items: center; }
          .reveal-text { font-size: 45px; }
        }
      `}</style>
    </div>
  );
